'kernel_size': nn.ValueChoice(
[3, 5],
label = f'fe_kernel_size_{i}'
)
}
# Feature Block Dimensions
if i == 0:
dim = (in_dimension, 8)
elif i == 1:
dim = (8, 16)
else:
dim = (16, 16)
params['dim'] = dim
params['activation'] = activation
return FeatureExtractionBlock(**params)
return create_block
